mod checkdigit_gtin___generate_harness {
    use super::*;
    #[test]
    fn gtin_generate__unit_test() {
        let unittests_file: std::fs::File = std::fs::File::open(
            "./exec-snapshots/(*github.com-osamingo-checkdigit.gtin).Generate.json",
        ).unwrap();
        let unittests_reader = std::io::BufReader::new(unittests_file);
        let unittests: Vec<ExecutionData> = serde_json::from_reader(unittests_reader).unwrap();
        #[serde_as]
        #[derive(Serialize, Deserialize)]
        struct InputState(Box<gtin>, Box<str>);
        #[serde_as]
        #[derive(Serialize)]
        struct OutputState(i32);
        for execution in unittests {
            let inputs_reserialized = if execution.inputs.len() == 1 {
                execution.inputs[0].clone()
            } else {
                serde_json::to_value(execution.inputs.clone()).unwrap()
            };
            let mut input_state: InputState = serde_json::from_value(inputs_reserialized).unwrap();
            struct NonCopyableMarker;
            let force_fn_once: NonCopyableMarker = NonCopyableMarker;
            let return_value = std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| {
                let _force_fn_once = force_fn_once;
                ((&*input_state.0).generate(&*input_state.1)).unwrap()
            }));
            match return_value {
                Ok(return_value) => {
                    assert!(execution.result.execution_success);
                    let output_state = OutputState(return_value);
                    assert_json_diff::assert_json_eq!(serde_json::to_value(output_state).unwrap(), execution.result.return_value.clone());
                    let inputs_mutation_reserialized = if execution.result.input_modifications.len() == 1 {
                        execution.result.input_modifications[0].clone()
                    } else {
                        serde_json::to_value(execution.result.input_modifications.clone()).unwrap()
                    };
                    let input_state_mutated: InputState = serde_json::from_value(inputs_mutation_reserialized).unwrap();
                    assert_json_diff::assert_json_eq!(serde_json::to_value(&input_state.0).unwrap(), serde_json::to_value(&input_state_mutated.0).unwrap());
                    assert_json_diff::assert_json_eq!(serde_json::to_value(&input_state.1).unwrap(), serde_json::to_value(&input_state_mutated.1).unwrap());
                }
                Err(_) => {
                    assert!(!execution.result.execution_success);
                }
            }
        }
    }
}

