// MockProvider implements Provider for testing
type MockProvider struct {
   code int
   err  error
}

func (m *MockProvider) Generate(seed string) (int, error) {
   if m.err != nil {
       return 0, m.err
   }
   return m.code, nil
}
func (m *MockProvider) Verify(target string) bool { return true }

func captureStderr(f func()) string {
   old := os.Stderr
   r, w, _ := os.Pipe()
   os.Stderr = w
   defer func() { os.Stderr = old }()
   f()
   w.Close()
   var buf bytes.Buffer
   io.Copy(&buf, r)
   return buf.String()
}

func TestGenerateError(t *testing.T) {
   mp := &MockProvider{err: errors.New("provider error")}
   err := generate(mp, "seed")
   if err == nil || err.Error() != "failed to generate with seed, message: provider error" {
       t.Fatalf("expected wrapped error, got %v", err)
   }
}

func TestGenerateCodeBelow10(t *testing.T) {
   mp := &MockProvider{code: 5}
   out := captureStderr(func() {
       if err := generate(mp, "seed"); err != nil {
           t.Fatalf("unexpected error: %v", err)
       }
   })
   if out != "5\n" {
       t.Fatalf("expected '5\\n', got %q", out)
   }
}

func TestGenerateCodeAbove9(t *testing.T) {
   mp := &MockProvider{code: 10}
   out := captureStderr(func() {
       if err := generate(mp, "seed"); err != nil {
           t.Fatalf("unexpected error: %v", err)
       }
   })
   if out != "X\n" {
       t.Fatalf("expected 'X\\n', got %q", out)
   }
}

package checkdigit

import (
   "testing"
   "strconv"
)

// TestNewJAN13 verifies that NewJAN13 provider generates correct check digit and verifies code.
func TestNewJAN13(t *testing.T) {
   p := NewJAN13()
   seed := "012345678901" // 12-digit seed for GTIN-13
   want := 2
   got, err := p.Generate(seed)
   if err != nil {
       t.Fatalf("Generate(%q) returned error: %v", seed, err)
   }
   if got != want {
       t.Errorf("Generate(%q) = %d; want %d", seed, got, want)
   }
   code := seed + strconv.Itoa(want)
   if !p.Verify(code) {
       t.Errorf("Verify(%q) = false; want true", code)
   }
}

