// captureStderr redirects stderr during f and returns the output.
func captureStderr(f func()) string {
	old := os.Stderr
	r, w, _ := os.Pipe()
	os.Stderr = w
	f()
	w.Close()
	var buf bytes.Buffer
	io.Copy(&buf, r)
	os.Stderr = old
	return buf.String()
}

// TestVerifyTrue checks that verify returns true and prints "true" to stderr.
func TestVerifyTrue(t *testing.T) {
	mp := mockProvider{ret: true}
	output := captureStderr(func() {
		if got := verify(mp, "anything"); !got {
			t.Errorf("verify returned false, want true")
		}
	})
	want := "true\n"
	if output != want {
		t.Errorf("stderr = %q, want %q", output, want)
	}
}

// TestVerifyFalse checks that verify returns false and prints "false" to stderr.
func TestVerifyFalse(t *testing.T) {
	mp := mockProvider{ret: false}
	output := captureStderr(func() {
		if got := verify(mp, "anything"); got {
			t.Errorf("verify returned true, want false")
		}
	})
	want := "false\n"
	if output != want {
		t.Errorf("stderr = %q, want %q", output, want)
	}
}

